76	// hardcoded. Lua's build system inserts the actual install prefix here.
77	#[cfg(not(target_os = "windows"))]
78	const LUA_PATH_DEFAULT: &[u8] =
79	    b"./?.lua;./?/init.lua;/usr/local/share/lua/5.4/?.lua;/usr/local/share/lua/5.4/?/init.lua";
80	#[cfg(target_os = "windows")]
81	const LUA_PATH_DEFAULT: &[u8] = b"./?.lua;./?/init.lua";
82	
