507	/// Push an error message listing all files in `path` that were not found.
508	///
509	/// Example output: `"no file 'a.lua'\n\tno file 'b.lua'"`
510	///
511	/// C: `static void pusherrornotfound(lua_State *L, const char *path)`
512	fn pusherrornotfound(state: &mut LuaState, path: &[u8]) -> Result<(), LuaError> {
513	    // C: luaL_Buffer b; luaL_buffinit(L, &b);
514	    let mut buf: Vec<u8> = Vec::new();
515	    // C: luaL_addstring(&b, "no file '");
516	    buf.extend_from_slice(b"no file '");
517	    // C: luaL_addgsub(&b, path, LUA_PATH_SEP, "'\n\tno file '");
518	    gsub_append(&mut buf, path, &[LUA_PATH_SEP], b"'\n\tno file '");
519	    // C: luaL_addstring(&b, "'");
520	    buf.push(b'\'');
521	    // C: luaL_pushresult(&b);
522	    let s = state.intern_str(&buf)?;
523	    state.push(LuaValue::Str(s));
524	    Ok(())
525	}
