578	/// `package.searchpath(name, path [, sep [, rep]])`.
579	///
580	/// Returns the first readable file in `path` with `sep` occurrences in `name`
581	/// replaced by `rep`. On failure returns `false` plus the error message.
582	///
583	/// C: `static int ll_searchpath(lua_State *L)`
584	pub fn ll_searchpath(state: &mut LuaState) -> Result<usize, LuaError> {
585	    // C: luaL_checkstring(L, 1) / luaL_checkstring(L, 2)
586	    let name = state.check_arg_string(1)?.to_vec();
587	    let path = state.check_arg_string(2)?.to_vec();
588	    // C: luaL_optstring(L, 3, ".")
589	    let sep = state.opt_arg_string(3, b".")?;
590	    // C: luaL_optstring(L, 4, LUA_DIRSEP)
591	    let dirsep_default = [LUA_DIRSEP];
592	    let dirsep = state.opt_arg_string(4, &dirsep_default)?;
593	
594	    let found = searchpath(state, &name, &path, &sep, &dirsep)?;
595	    if found.is_some() {
596	        // C: if (f != NULL) return 1;
597	        return Ok(1);
598	    }
599	    // C: luaL_pushfail(L); lua_insert(L, -2); return 2;
600	    state.push(LuaValue::Bool(false));
601	    state.insert(-2);
602	    Ok(2)
603	}
