605	/// Find a module file using the path stored in `package[pname]`.
606	///
607	/// C: `static const char *findfile(lua_State *L, const char *name,
608	///                                  const char *pname, const char *dirsep)`
609	///
610	/// TODO(port): Should return `Result<Option<Vec<u8>>, LuaError>` to properly
611	/// propagate the `"'package.<pname>' must be a string"` error. Currently returns
612	/// `None` and loses the error, which will cause a confusing failure downstream.
613	fn findfile(state: &mut LuaState, name: &[u8], pname: &[u8], dirsep: u8) -> Result<Option<Vec<u8>>, LuaError> {
614	    // C: lua_getfield(L, lua_upvalueindex(1), pname);
615	    // The package table is upvalue #1 for the searcher closures.
616	    let uv = state.upvalue_index(1);
617	    let _ = state.get_field(uv, pname);
618	    // C: path = lua_tostring(L, -1);
619	    let path_opt: Option<Vec<u8>> = state.to_bytes(-1);
620	    let Some(path) = path_opt else {
621	        // C: if (l_unlikely(path == NULL)) luaL_error(L, "'package.%s' must be a string", pname);
622	        // TODO(port): Cannot return Err here without changing the signature.
623	        //             For now pop the nil and return None (error is silently dropped).
624	        state.pop_n(1);
625	        return Ok(None);
626	    };
627	    state.pop_n(1);
628	    searchpath(state, name, &path, b".", &[dirsep])
629	}
