631	/// Check whether a module load succeeded, returning the open function + filename
632	/// (2 values) on success or raising an error on failure.
633	///
634	/// C: `static int checkload(lua_State *L, int stat, const char *filename)`
635	fn checkload(state: &mut LuaState, stat: bool, filename: &[u8]) -> Result<usize, LuaError> {
636	    if stat {
637	        // C: lua_pushstring(L, filename);
638	        let s = state.intern_str(filename)?;
639	        state.push(LuaValue::Str(s));
640	        // C: return 2;
641	        Ok(2)
642	    } else {
643	        // C: return luaL_error(L, "error loading module '%s' from file '%s':\n\t%s",
644	        //                         lua_tostring(L, 1), filename, lua_tostring(L, -1));
645	        // PORT NOTE: The error message in C embeds the module name (stack[1]) and
646	        // the loader error message (stack top). In Rust we read those byte slices.
647	        // TODO(port): state.to_bytes(1) and state.to_bytes(-1) borrow from the
648	        //             stack simultaneously; in Phase B use index-snapshot clones.
649	        let modname = state.to_bytes(1).unwrap_or_else(|| b"?".to_vec());
650	        let loader_err = state.to_bytes(-1).unwrap_or_else(|| b"?".to_vec());
651	
652	        let mut msg = b"error loading module '".to_vec();
653	        msg.extend_from_slice(&modname);
654	        msg.extend_from_slice(b"' from file '");
655	        msg.extend_from_slice(filename);
656	        msg.extend_from_slice(b"':\n\t");
657	        msg.extend_from_slice(&loader_err);
658	
659	        // PERF(port): builds a heap Vec then interns; in Phase B use push_fstring.
660	        let s = state.intern_str(&msg)?;
661	        return Err(LuaError::from_value(LuaValue::Str(s)));
662	    }
663	}
