667	/// Searcher that looks in `package.path` for a Lua source file.
668	///
669	/// Returns 1 value (error-message string) if not found, or 2 values (loader
670	/// function, filename) if found and loaded successfully.
671	///
672	/// C: `static int searcher_Lua(lua_State *L)`
673	fn searcher_lua(state: &mut LuaState) -> Result<usize, LuaError> {
674	    // C: const char *name = luaL_checkstring(L, 1);
675	    let name = state.check_arg_string(1)?.to_vec();
676	    // C: filename = findfile(L, name, "path", LUA_LSUBSEP);
677	    let filename = findfile(state, &name, b"path", LUA_LSUBSEP)?;
678	    if filename.is_none() {
679	        // C: if (filename == NULL) return 1;  -- error message on stack
680	        return Ok(1);
681	    }
682	    let filename = filename.unwrap();
683	    // C: return checkload(L, (luaL_loadfile(L, filename) == LUA_OK), filename);
684	    //
685	    // PORT NOTE: `std::fs` is banned in `lua-stdlib`, so file contents come in
686	    // via the embedder-registered `file_loader_hook` on `GlobalState`. We then
687	    // parse them through `state.load(...)` (which dispatches to the parser
688	    // hook) and place the resulting closure on the stack so `checkload` can
689	    // pair it with the filename.
690	    let chunk = match state.global().file_loader_hook {
691	        Some(hook) => hook(&filename),
692	        None => Err(LuaError::runtime(format_args!(
693	            "no file_loader_hook registered; cannot read '{}'",
694	            String::from_utf8_lossy(&filename)
695	        ))),
696	    };
697	    let load_ok = match chunk {
698	        Ok(bytes) => {
699	            // Use a chunk name of the form `@filename` matching C's luaL_loadfilex.
700	            let mut chunkname = b"@".to_vec();
701	            chunkname.extend_from_slice(&filename);
702	            match state.load(&bytes, &chunkname, None) {
703	                Ok(true) => true,
704	                Ok(false) => false,
705	                Err(e) => {
706	                    let msg = match e {
707	                        LuaError::Syntax(LuaValue::Str(ref s))
708	                        | LuaError::Runtime(LuaValue::Str(ref s)) => s.as_bytes().to_vec(),
709	                        other => format!("{:?}", other).into_bytes(),
710	                    };
711	                    let s = state.intern_str(&msg)?;
712	                    state.push(LuaValue::Str(s));
713	                    false
714	                }
715	            }
716	        }
717	        Err(e) => {
718	            let msg = match e {
719	                LuaError::Runtime(LuaValue::Str(ref s)) => s.as_bytes().to_vec(),
720	                other => format!("{:?}", other).into_bytes(),
721	            };
722	            let s = state.intern_str(&msg)?;
723	            state.push(LuaValue::Str(s));
724	            false
725	        }
726	    };
727	    checkload(state, load_ok, &filename)
728	}
