766	/// Searcher that looks in `package.cpath` for a C dynamic library.
767	///
768	/// C: `static int searcher_C(lua_State *L)`
769	fn searcher_c(state: &mut LuaState) -> Result<usize, LuaError> {
770	    // C: const char *name = luaL_checkstring(L, 1);
771	    let name = state.check_arg_string(1)?.to_vec();
772	    // C: const char *filename = findfile(L, name, "cpath", LUA_CSUBSEP);
773	    let filename = findfile(state, &name, b"cpath", LUA_CSUBSEP)?;
774	    if filename.is_none() {
775	        // C: if (filename == NULL) return 1;
776	        return Ok(1);
777	    }
778	    let filename = filename.unwrap();
779	    // C: return checkload(L, (loadfunc(L, filename, name) == 0), filename);
780	    let stat = loadfunc(state, &filename, &name)?;
781	    checkload(state, stat == 0, &filename)
782	}
