872	// ── require implementation ────────────────────────────────────────────────────
873	
874	/// Iterate through `package.searchers` to find a loader for module `name`.
875	///
876	/// On success, leaves `(loader_function, loader_data)` at the top of the stack
877	/// (below the searchers table). On failure, raises a runtime error.
878	///
879	/// C: `static void findloader(lua_State *L, const char *name)`
880	///
881	/// TODO(port): The exact absolute stack indices used in C (index 3 for the
882	/// searchers table) depend on the caller (`ll_require`) having set up the
883	/// stack in a specific way. In Rust we use relative indices. The behaviour
884	/// should match C but the index arithmetic must be verified in Phase B.
885	fn findloader(state: &mut LuaState, name: &[u8]) -> Result<(), LuaError> {
886	    // C: if (lua_getfield(L, lua_upvalueindex(1), "searchers") != LUA_TTABLE)
887	    //        luaL_error(L, "'package.searchers' must be a table");
888	    let uv = state.upvalue_index(1);
889	    let ty = state.get_field(uv, b"searchers")?;
890	    if ty != LuaType::Table {
891	        return Err(LuaError::runtime(format_args!(
892	            "'package.searchers' must be a table"
893	        )));
894	    }
895	    // Searchers table is now at the top of the stack.
896	
897	    // C: luaL_buffinit(L, &msg);
898	    let mut msg_buf: Vec<u8> = Vec::new();
899	
900	    let mut i: i64 = 1;
901	    loop {
902	        // C: luaL_addstring(&msg, "\n\t");
903	        msg_buf.extend_from_slice(b"\n\t");
904	
905	        // C: if (lua_rawgeti(L, 3, i) == LUA_TNIL) { ... no more searchers }
906	        // PORT NOTE: In C the searchers table is at absolute index 3. In Rust
907	        // it is at -1 (relative to the top). TODO(port): verify this is correct
908	        // after accounting for whatever else the caller left on the stack.
909	        let item_ty = state.raw_geti(-1, i)?;
910	        if item_ty == LuaType::Nil {
911	            // C: lua_pop(L, 1);  -- remove nil
912	            state.pop_n(1);
913	            // C: luaL_buffsub(&msg, 2);
914	            let len = msg_buf.len();
915	            if len >= 2 {
916	                msg_buf.truncate(len - 2);
917	            }
918	            // C: luaL_pushresult(&msg); luaL_error(L, "module '%s' not found:%s", ...)
919	            // Build the error message as a Lua string then raise.
920	            let mut err = b"module '".to_vec();
921	            err.extend_from_slice(name);
922	            err.extend_from_slice(b"' not found:");
923	            err.extend_from_slice(&msg_buf);
924	            let err_s = state.intern_str(&err)?;
925	            return Err(LuaError::from_value(LuaValue::Str(err_s)));
926	        }
927	
928	        // C: lua_pushstring(L, name);
929	        let name_s = state.intern_str(name)?;
930	        state.push(LuaValue::Str(name_s));
931	
932	        // C: lua_call(L, 1, 2);
933	        state.call(1, 2)?;
934	
935	        // After call: two return values r1 (at -2) and r2 (at -1) on top.
936	        // C: if (lua_isfunction(L, -2)) return;
937	        if state.type_at(-2) == LuaType::Function {
938	            // Loader found; leave (r1=function, r2=data) on stack and return.
939	            return Ok(());
940	        }
941	
942	        // C: else if (lua_isstring(L, -2)) { lua_pop(L, 1); luaL_addvalue(&msg); }
943	        if state.type_at(-2) == LuaType::String {
944	            // r1 is an error-message string from the searcher.
945	            // C: lua_pop(L, 1)  -- remove r2 (the extra/nil return)
946	            state.pop_n(1);
947	            // C: luaL_addvalue(&msg)  -- append r1 (now at -1) to msg, pop it
948	            if let Some(bytes) = state.to_bytes(-1) {
949	                msg_buf.extend_from_slice(&bytes);
950	            }
951	            state.pop_n(1);
952	        } else {
953	            // C: lua_pop(L, 2);  -- remove both returns (no error message)
954	            state.pop_n(2);
955	            // C: luaL_buffsub(&msg, 2);  -- remove the "\n\t" prefix
956	            let len = msg_buf.len();
957	            if len >= 2 {
958	                msg_buf.truncate(len - 2);
959	            }
960	        }
961	
962	        i += 1;
963	    }
964	}
