48	fn parser_hook(
49	    state: &mut LuaState,
50	    source: &[u8],
51	    name: &[u8],
52	    firstchar: i32,
53	) -> Result<GcRef<LuaLClosure>, LuaError> {
54	    let proto = lua_parse::parse(
55	        state,
56	        lua_parse::DynData::default(),
57	        source,
58	        name,
59	        firstchar,
60	    )?;
61	    let nupvals = proto.upvalues.len();
62	    let mut upvals = Vec::with_capacity(nupvals);
63	    for _ in 0..nupvals {
64	        upvals.push(GcRef::new(UpVal::closed(LuaValue::Nil)));
65	    }
66	    Ok(GcRef::new(LuaLClosure {
67	        proto: GcRef::new(*proto),
68	        upvals,
69	    }))
