77	            LuaValue::Str(s) => format!("{}: {}", e_tag(e), String::from_utf8_lossy(s.as_bytes())),
78	            other => format!("{}: {:?}", e_tag(e), other),
79	        },
80	        LuaError::Memory | LuaError::Error | LuaError::Yield
81	        | LuaError::File | LuaError::Gc => format!("{}", e_tag(e)),
82	    }
83	}
